// OcasionPlus - enricher: ficha (Next.js RSC stream) -> vehicle object -> UPDATE
const httpOut = $input.item.json;
let html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
const id = $('Loop: coche por coche').item.json.id;
function esc(v){ if(v===null||v===undefined||v==='') return null; return "'"+String(v).replace(/'/g,"''")+"'"; }
// des-escapar el stream RSC
const un = html.replace(/\\"/g,'"').replace(/\\\\/g,'\\').replace(/\\u002F/gi,'/');
// color (anclado en "metallic" para no coger la etiqueta i18n "Color")
let color=''; { const m=un.match(/"color"\s*:\s*"([^"]{1,40})"\s*,\s*"metallic"/); if(m) color=m[1].trim(); }
// carroceria
let body=''; { const m=un.match(/"bodyStyle"\s*:\s*"([^"]{1,40})"/); if(m) body=m[1].trim(); }
// puertas / plazas (numericos -> saltan la etiqueta string)
let doors=null; { const m=un.match(/"doors"\s*:\s*(\d+)/); if(m) doors=parseInt(m[1],10); }
let seats=null; { const m=un.match(/"seats"\s*:\s*(\d+)/); if(m) seats=parseInt(m[1],10); }
// etiqueta medioambiental
let etiqueta=''; { const m=un.match(/"environmentalLabel"\s*:\s*"([^"]{1,20})"/); if(m && !/undefined/i.test(m[1])) etiqueta=m[1].trim(); }
// engine: cilindrada (cc), potencia (cv), traccion (drive bool)
let cc='', cv=null, drive=null;
{ const em=un.match(/"engine"\s*:\s*\{([^}]*)\}/); if(em){ const e=em[1];
    const mc=e.match(/"cc"\s*:\s*"?(\d+)"?/); if(mc) cc=mc[1];
    const mv=e.match(/"cv"\s*:\s*(\d+)/); if(mv) cv=parseInt(mv[1],10);
    const md=e.match(/"drive"\s*:\s*(true|false)/); if(md) drive=(md[1]==='true');
} }
// consumo (consumption.combined, L/100)
let consumo=null; { const m=un.match(/"consumption"\s*:\s*\{[^}]*?"combined"\s*:\s*"?([\d.,]+)"?/); if(m){ const n=parseFloat(String(m[1]).replace(',','.')); if(!isNaN(n)) consumo=n; } }
// co2 (emissions.WLTP preferido, si no combustion)
let co2=''; { const m=un.match(/"emissions"\s*:\s*\{([^}]*)\}/); if(m){ const e=m[1];
    const w=e.match(/"WLTP"\s*:\s*"?(\d+)"?/); const cb=e.match(/"combustion"\s*:\s*"?(\d+)"?/);
    if(w && w[1]) co2=w[1]; else if(cb && cb[1]) co2=cb[1];
} }
// traccion: OcasionPlus solo expone flag 4x4 si/no (drive). Solo afirmamos 4x4 cuando es true.
let traction=''; if(drive===true) traction='4x4';
// construir UPDATE
const sets=[];
if(esc(color)) sets.push('color='+esc(color));
if(esc(body)) sets.push('body_type='+esc(body));
if(doors!=null) sets.push('doors='+doors);
if(seats!=null) sets.push('seats='+seats);
if(esc(cc)) sets.push('displacement='+esc(cc));
if(cv!=null && cv>0) sets.push('power_cv='+cv);
if(consumo!=null) sets.push('consumption='+consumo);
if(esc(co2)) sets.push('co2='+esc(co2));
if(esc(etiqueta)) sets.push('environmental_label='+esc(etiqueta));
if(esc(traction)) sets.push('traction='+esc(traction));
if(!sets.length) return [{ json:{ sql:null, count:0 } }];
sets.push('last_seen_at=NOW()','updated_at=NOW()');
const sql='UPDATE moveadvisor_market_offers SET '+sets.join(', ')+' WHERE id='+esc(id);
return [{ json:{ sql:sql, count:1 } }];
